"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[328698],{543576:e=>{e.exports=JSON.parse('{"tag":{"label":"leader","permalink":"/dst-api-webdocs/docs/tags/leader","allTagsPath":"/dst-api-webdocs/docs/tags","count":10,"items":[{"id":"game-scripts/prefabs/beef_bell","title":"Beef Bell","description":"Manages the logic for the Beef Bell item, including linking to a beefalo, inventory interactions, revive functionality for the Shadow Beef Bell variant, and synchronization between server and client.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beef_bell"},{"id":"game-scripts/components/follower","title":"Follower","description":"Manages an entity\'s relationship to a leader, including loyalty mechanics, teleportation on separation, and handling player reconnection or respawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/follower"},{"id":"game-scripts/components/follower_replica","title":"Follower Replica","description":"Manages networked references to an entity\'s leader or item owner for follower behavior synchronization between client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/follower_replica"},{"id":"game-scripts/components/followerherder","title":"Followerherder","description":"Manages herd behavior for a leader entity, toggling hostile state of all followers and consuming finite uses when triggered.","permalink":"/dst-api-webdocs/docs/game-scripts/components/followerherder"},{"id":"game-scripts/components/followermemory","title":"Followermemory","description":"Remembers and tracks a follower\'s last known leader across sessions and entity state changes, enabling reunification when the leader returns.","permalink":"/dst-api-webdocs/docs/game-scripts/components/followermemory"},{"id":"game-scripts/prefabs/fruitfly","title":"Fruitfly","description":"Manages fruit fly entities with distinct behaviors for hostile lord/mini variants, friendly companions, and seed-bearing fruit fly fruit that spawn companions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fruitfly"},{"id":"game-scripts/prefabs/glommerflower","title":"Glommerflower","description":"Acts as a leader for Glommer entities and tracks their life state, transforming into a dead flower when Glommer leaves or dies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommerflower"},{"id":"game-scripts/brains/monkeybrain","title":"Monkeybrain","description":"AI brain controller for monkey characters that manages combat, foraging, item gathering, leash behavior, and leader harassment via behavior tree logic.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/monkeybrain"},{"id":"game-scripts/prefabs/rabbitking","title":"Rabbitking","description":"Implements the Rabbit King and its minions, including passive (shopkeeper), aggressive (combat-focused), bunnyman minion, and lucky (trap-catchable) variants with associated combat, leadership, and transformation logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitking"},{"id":"game-scripts/prefabs/warglet","title":"Warglet","description":"A hostile hound-like boss entity that spawns additional hounds, coordinates a pack, and transitions between land and water locomotion.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/warglet"}],"unlisted":false}}')}}]);